#include <stdio.h>

typedef struct {
    int code;
    char title[101];
    double price;
} Book;

void display(const Book *b) {
    printf("Code: %d\n", b->code);
    printf("Title: %s\n", b->title);
    printf("Price: %.2f\n", b->price);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        Book b;
        scanf("%d %100s %lf", &b.code, b.title, &b.price);
        display(&b);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

class Book {
public:
    int code;
    string title;
    double price;
    Book(int c, const string &t, double p) : code(c), title(t), price(p) {}
    void display() const {
        cout << "Code: " << code << '\n';
        cout << "Title: " << title << '\n';
        cout << fixed << setprecision(2);
        cout << "Price: " << price << '\n';
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        int code; string title; double price;
        cin >> code >> title >> price;
        Book b(code, title, price);
        b.display();
    }
    return 0;
}

code.Java:
import java.util.*;

class Book {
    int code;
    String title;
    double price;
    Book(int code, String title, double price) {
        this.code = code;
        this.title = title;
        this.price = price;
    }
    void display() {
        System.out.println("Code: " + code);
        System.out.println("Title: " + title);
        System.out.printf("Price: %.2f\n", price);
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        for (int i = 0; i < T; i++) {
            int code = sc.nextInt();
            String title = sc.next();
            double price = sc.nextDouble();
            Book b = new Book(code, title, price);
            b.display();
        }
        sc.close();
    }
}

