let idx = 0;
const T = parseInt(input[idx++], 10);
let out = [];
for (let i = 0; i < T; i++) {
  const code = parseInt(input[idx++], 10);
  const title = input[idx++];
  const price = parseFloat(input[idx++]);
  out.push(`Code: ${code}`);
  out.push(`Title: ${title}`);
  out.push(`Price: ${price.toFixed(2)}`);
}
